[
  {
    "text": "The systematic review searched six academic databases and organizational repositories for studies on Climate Change Education (CCE) published between 2015 and 2025.",
    "topic": "Climate Change Education systematic review methodology"
  },
  {
    "text": "Out of 1,420 records identified, a total of 1,420 studies were screened, and a subset was included in the systematic review.",
    "topic": "Study selection in systematic review"
  },
  {
    "text": "The review addresses pedagogical effectiveness, assessment innovations, policy alignment, and scaling strategies for CCE in K–12 and higher education.",
    "topic": "Aspects of Climate Change Education covered in the review"
  },
  {
    "text": "The review follows PRISMA 2020 guidelines for conducting systematic reviews.",
    "topic": "Methodological standards of the review"
  },
  {
    "text": "The review synthesizes evidence on Climate Change Education across basic and higher education, focusing on learning outcomes and policy alignment.",
    "topic": "Scope of the Climate Change Education review"
  }
]
